mapper.select:
SELECT sdd.id, sdd.label, sdd.`value`, sdd.is_default, sdd.sort_order, sdd.`status` FROM sys_dict_data sdd WHERE sdd.del_flag = '0' AND sdd.parent_id = #{request.parentId}
AND ( sdd.code LIKE concat('%', #{request.keyword}, '%') OR sdd.label LIKE concat('%', #{request.keyword}, '$') )
AND sdd.status = #{request.status}
